<template><ModulePageShell title="低体温专项" description="读取结构化事件、术中体温与PACU入室体温"><template #chips><a-tag color="red">低体温病例 {{result.total}}</a-tag></template><template #toolbar><a-button :loading="loading" @click="reload">刷新</a-button></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-empty v-else-if="!loading&&!result.total" description="当前范围无低体温证据"/><a-card v-else class="section-card" :bordered="false" title="低体温病例"><a-table :data="result.list" row-key="caseId" :pagination="{pageSize:10}"><a-table-column title="患者" data-index="patientName"/><a-table-column title="手术" data-index="operationName"/><a-table-column title="手术间" data-index="room"/><a-table-column title="麻醉方式" data-index="anesthesiaMethod"/><a-table-column title="结构化证据"><template #cell="{record}"><div v-for="(ev,i) in record.evidence" :key="i">{{evidence(ev)}}</div></template></a-table-column><a-table-column title="操作"><template #cell="{record}"><a-link @click="router.push(`/surgery/detail/${record.caseId}`)">病例穿透</a-link></template></a-table-column></a-table></a-card></ModulePageShell></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{useRouter}from'vue-router';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{qualityApi,type QualityHypothermiaEvidenceApi,type QualityHypothermiaResultApi}from'@/api/quality';const router=useRouter(),loading=ref(false),error=ref(''),result=reactive<QualityHypothermiaResultApi>({total:0,list:[]});async function reload(){loading.value=true;error.value='';try{Object.assign(result,await qualityApi.getHypothermiaCases());}catch(e){Object.assign(result,{total:0,list:[]});error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}function evidence(ev:QualityHypothermiaEvidenceApi){if(ev.source==='event')return`事件：${ev.type??'低体温'}`;if(ev.source==='vital_temp')return`术中最低体温：${ev.min??'—'}℃`;return`PACU入室体温：${ev.value??'—'}℃`;}onMounted(reload);</script>
